query.value:
SELECT ?name ?mRID WHERE {
 ?s r:type c:EquipmentContainer.
 ?s c:IdentifiedObject.name ?name.
 ?s c:IdentifiedObject.mRID ?mRID.
}
ORDER by ?name

SELECT DISTINCT ?nominalVoltage WHERE {
 ?sys c:IdentifiedObject.mRID ?EquipmentContainer_mRID.
 ?s c:Equipment.EquipmentContainer ?sys.
 {?s c:ConductingEquipment.BaseVoltage ?lev.}
  UNION
 { ?end c:PowerTransformerEnd.PowerTransformer ?s.
   ?end c:TransformerEnd.BaseVoltage ?lev.}
 ?lev r:type c:BaseVoltage.
 ?lev c:BaseVoltage.nominalVoltage ?vstr.
  bind(xsd:string(?vstr) as ?xsdstr)
  bind(xsd:float(?xsdstr) as ?nominalVoltage)
}
ORDER BY ?nominalVoltage

SELECT DISTINCT ?mRID ?p ?q WHERE {
 ?sv e:SvPowerFlow.TransformerEnd ?end.
  bind(substr(str(?end),strlen(str(?end))-35) as ?mRID)
 ?sv c:SvPowerFlow.p ?p.
 ?sv c:SvPowerFlow.q ?q.
} ORDER BY ?mRID

SELECT DISTINCT ?mRID ?name ?Equipment_mRID ?Equipment_type WHERE {
 ?p r:type e:RotatingMachinePlant.
 ?p c:IdentifiedObject.name ?name.
 ?p c:IdentifiedObject.mRID ?mRID.
 ?p e:ConnectedFacility.Equipments ?eq.
 ?eq c:IdentifiedObject.mRID ?Equipment_mRID.
 {?eq a ?rawtype.
  bind(strafter(str(?rawtype),"#") as ?Equipment_type)}
} ORDER by ?mRID ?Equipment_type ?Equipment_mRID

SELECT DISTINCT ?mRID ?dllSequenceNumber ?dllName ?dllWidth ?dllParameterKind ?kind ?sensorRatio ?unit ?multiplier ?phase ?ConnectivityNode_mRID ?DCNode_mRID ?ACDCTerminal_mRID WHERE {
 ?sys c:IdentifiedObject.mRID ?EquipmentContainer_mRID.
 ?eq r:type c:PowerElectronicsConnection.
 ?eq c:Equipment.EquipmentContainer ?sys.
 ?d c:DetailedModelDynamics.Equipment ?eq.
 ?d c:IdentifiedObject.mRID ?mRID.
 ?p c:SignalDescriptor.DynamicsFunctionBlock ?d.
 ?p e:IEEECigreDLLSignal.dllSequenceNumber ?dllSequenceNumber.
 ?p e:IEEECigreDLLInput.sensorRatio ?sensorRatio.
 ?p e:IEEECigreDLLSignal.dllName ?dllName.
 ?p e:IEEECigreDLLSignal.dllWidth ?dllWidth.
 {?p e:IEEECigreDLLSignal.unit ?rawunit.
  bind(strafter(str(?rawunit),"UnitSymbol.") as ?unit)}
 {?p e:IEEECigreDLLSignal.multiplier ?rawmult.
  bind(strafter(str(?rawmult),"UnitMultiplier.") as ?multiplier)}
 OPTIONAL {?p e:IEEECigreDLLSignal.phase ?rawphase.
  bind(strafter(str(?rawphase),"Kind.") as ?phase)}
 {?p e:IEEECigreDLLSignal.dllParameterKind ?rawkind.
  bind(strafter(str(?rawkind),"Kind.") as ?dllParameterKind)}
 {?p e:IEEECigreDLLInput.kind ?rawsig.
  bind(strafter(str(?rawsig),"Kind.") as ?kind)}
 OPTIONAL {?p e:IEEECigreDLLSignal.ConnectivityNode ?cn.
           ?cn c:IdentifiedObject.mRID ?ConnectivityNode_mRID}
 OPTIONAL {?p e:IEEECigreDLLSignal.DCNode ?dcn.
           ?dcn c:IdentifiedObject.mRID ?DCNode_mRID}
 OPTIONAL {?p c:SignalDescriptor.ACDCTerminal ?trm.
          bind(substr(str(?trm),strlen(str(?trm))-37,38) as ?ACDCTerminal_mRID)}
} ORDER by ?mRID ?dllSequenceNumber

SELECT DISTINCT ?mRID ?dllSequenceNumber ?dllName ?dllWidth ?dllParameterKind ?kind ?scalingRatio ?unit ?multiplier ?phase ?ConnectivityNode_mRID ?DCNode_mRID ?ACDCTerminal_mRID WHERE {
 ?sys c:IdentifiedObject.mRID ?EquipmentContainer_mRID.
 ?eq r:type c:PowerElectronicsConnection.
 ?eq c:Equipment.EquipmentContainer ?sys.
 ?d c:DetailedModelDynamics.Equipment ?eq.
 ?d c:IdentifiedObject.mRID ?mRID.
 ?p c:SignalDescriptor.DynamicsFunctionBlock ?d.
 ?p e:IEEECigreDLLSignal.dllSequenceNumber ?dllSequenceNumber.
 ?p e:IEEECigreDLLOutput.scalingRatio ?scalingRatio.
 ?p e:IEEECigreDLLSignal.dllName ?dllName.
 ?p e:IEEECigreDLLSignal.dllWidth ?dllWidth.
 {?p e:IEEECigreDLLSignal.unit ?rawunit.
  bind(strafter(str(?rawunit),"UnitSymbol.") as ?unit)}
 {?p e:IEEECigreDLLSignal.multiplier ?rawmult.
  bind(strafter(str(?rawmult),"UnitMultiplier.") as ?multiplier)}
 OPTIONAL {?p e:IEEECigreDLLSignal.phase ?rawphase.
  bind(strafter(str(?rawphase),"Kind.") as ?phase)}
 {?p e:IEEECigreDLLSignal.dllParameterKind ?rawkind.
  bind(strafter(str(?rawkind),"Kind.") as ?dllParameterKind)}
 {?p e:IEEECigreDLLOutput.kind ?rawsig.
  bind(strafter(str(?rawsig),"Kind.") as ?kind)}
 OPTIONAL {?p e:IEEECigreDLLSignal.ConnectivityNode ?cn.
           ?cn c:IdentifiedObject.mRID ?ConnectivityNode_mRID}
 OPTIONAL {?p e:IEEECigreDLLSignal.DCNode ?dcn.
           ?dcn c:IdentifiedObject.mRID ?DCNode_mRID}
 OPTIONAL {?p c:SignalDescriptor.ACDCTerminal ?trm.
          bind(substr(str(?trm),strlen(str(?trm))-37,38) as ?ACDCTerminal_mRID)}
} ORDER by ?mRID ?dllSequenceNumber

SELECT ?mRID ?name WHERE {
 ?s r:type c:EquipmentContainer.
 ?s c:IdentifiedObject.mRID ?mRID.
 ?s c:IdentifiedObject.name ?name
}
ORDER BY ?name

SELECT ?mRID ?name WHERE {
 ?s r:type c:DCEquipmentContainer.
 ?s c:IdentifiedObject.mRID ?mRID.
 ?s c:IdentifiedObject.name ?name
}
ORDER BY ?name

SELECT DISTINCT ?name ?mRID ?DCEquipmentContainer_mRID WHERE {
 VALUES ?DCEquipmentContainer_mRID {"61A2E499-3BBB-4251-9FFE-929EC7F6A2EA"^^c:String}
 ?sys c:IdentifiedObject.mRID ?DCEquipmentContainer_mRID.
 ?s c:DCNode.DCEquipmentContainer ?sys.
 ?s r:type c:DCNode.
 ?s c:IdentifiedObject.name ?name.
 ?s c:IdentifiedObject.mRID ?mRID
}
ORDER by ?name
